      {
        "label": "SHAP 值解释",
        "latex": "\\phi_j = \\sum_{S \\subseteq N \\setminus \\{j\\}} \\frac{|S|!(|N|-|S|-1)!}{|N|!} \\left[f(S \\cup \\{j\\}) - f(S)\\right]"
      }
